import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  useEffect(() => {
    if (pacienteEditando) {
      setNome(pacienteEditando.nome || '');
      setTelefone(pacienteEditando.telefone || '');
    } else {
      setNome('');
      setTelefone('');
    }
  }, [pacienteEditando]);

  const handleSubmit = (e) => {
    e.preventDefault();
    const dados = { nome, telefone };
    if (pacienteEditando) {
      axios.put(`/api/pacientes/${pacienteEditando.id}`, dados)
        .then(() => {
          setMensagem('Paciente atualizado!');
          onNovoPaciente();
          onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar paciente.'));
    } else {
      axios.post('/api/pacientes', dados)
        .then(() => {
          setMensagem('Paciente cadastrado!');
          onNovoPaciente();
          setNome('');
          setTelefone('');
        })
        .catch(() => setMensagem('Erro ao cadastrar paciente.'));
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6 shadow-md">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={nome}
              onChange={e => setNome(e.target.value)}
              placeholder="Nome completo"
            />
          </label>
        </div>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
            <input
              className="w-full border rounded px-3 py-2 mt-1"
              required
              value={telefone}
              onChange={e => setTelefone(e.target.value)}
              placeholder="(XX) XXXXX-XXXX"
              type="tel"
            />
          </label>
        </div>
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>
        {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
      </form>
    </div>
  );
}

export default FormPaciente;
